import{_ as l,o as e,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"12.5 小结","description":"","frontmatter":{},"headers":[],"relativePath":"12/5.md","filePath":"12/5.md","lastUpdated":null}'),r={name:"12/5.md"};function n(o,a,s,_,d,p){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_12-5-小结" tabindex="-1">12.5 小结 <a class="header-anchor" href="#_12-5-小结" aria-label="Permalink to &quot;12.5 小结&quot;">​</a></h1><p>本章讨论了如何部署和维护我们开发的Web应用相关的一些话题。这些内容非常重要，要创建一个能够基于最小维护平滑运行的应用，必须考虑这些问题。</p><p>具体而言，本章讨论的内容包括：</p><ul><li>创建一个强健的日志系统，可以在出现问题时记录错误并且通知系统管理员</li><li>处理运行时可能出现的错误，包括记录日志，并如何友好的显示给用户系统出现了问题</li><li>处理404错误，告诉用户请求的页面找不到</li><li>将应用部署到一个生产环境中(包括如何部署更新)</li><li>如何让部署的应用程序具有高可用</li><li>备份和恢复文件以及数据库</li></ul><p>读完本章内容后，对于从头开始开发一个Web应用需要考虑那些问题，你应该已经有了全面的了解。本章内容将有助于你在实际环境中管理前面各章介绍开发的代码。</p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/12/4.html">备份和恢复</a></li><li>下一节: <a href="/13/0.html">如何设计一个Web框架</a></li></ul>',7)])])}const u=l(r,[["render",n]]);export{h as __pageData,u as default};
